#!/usr/bin/perl
use strict;
use warnings;
use CGI;

my $cgi = new CGI;

my $log_dir = '/path/to/log/files';
my $filename = $cgi->param('logfile');

print $cgi->header,
      $cgi->start_html('Log Viewer'),
      $cgi->h1('Log Viewer');

if ($filename =~ /^[\w.-]+$/) {
    if(open(FH, '<', "$log_dir/$filename")) { 
        while(my $line = <FH>) { 
            print $cgi->p($line); 
        } 
        close(FH); 
    } else {  
        print $cgi->p('Unable to open log file.'); 
    }
} else {
    print $cgi->p('Invalid log file name.');
}

print $cgi->end_html;